import React from "react";

// Dentes permanentes (superior e inferior, formato FDI)
const dentesPermanentes = [
  [18, 17, 16, 15, 14, 13, 12, 11, 21, 22, 23, 24, 25, 26, 27, 28],
  [48, 47, 46, 45, 44, 43, 42, 41, 31, 32, 33, 34, 35, 36, 37, 38]
];

export default function OdontogramaAvancado({
  tratamentos = [],
  onSelecionarDente,
  denteSelecionado,
}) {
  const dentes = dentesPermanentes; // só permanentes, mas fácil de adicionar decíduos

  // Pega status do tratamento por dente (aberto, finalizado)
  function getStatusDente(num) {
    const t = tratamentos.find(
      t =>
        t.dente === String(num) ||
        (Array.isArray(t.dente) && t.dente.includes(String(num)))
    );
    if (!t) return "";
    return t.status === "finalizado" ? "finalizado" : "aberto";
  }

  return (
    <div className="w-full flex flex-col items-center p-4 bg-white rounded-2xl shadow">
      {/* Dentes */}
      <div className="flex flex-col gap-4 items-center">
        {dentes.map((linha, idx) => (
          <div key={idx} className="flex flex-row gap-2 justify-center">
            {linha.map(num => (
              <DenteSVG
                key={num}
                numero={num}
                status={getStatusDente(num)}
                selecionado={denteSelecionado === String(num)}
                onClick={() => onSelecionarDente(String(num))}
              />
            ))}
          </div>
        ))}
      </div>
      {/* Legenda */}
      <div className="flex gap-4 mt-6 mb-2 justify-center">
        <Legenda cor="#fbbf24" texto="Aberto 🦷" />
        <Legenda cor="#a3e635" texto="Finalizado 🦷" />
        <Legenda cor="#6366f1" texto="Anotações !" />
      </div>
    </div>
  );
}

function DenteSVG({ numero, status, selecionado, onClick }) {
  const cor =
    status === "finalizado"
      ? "#a3e635"
      : status === "aberto"
      ? "#fbbf24"
      : selecionado
      ? "#3b82f6"
      : "#fff";
  const stroke =
    selecionado || status ? "#3b82f6" : "#bbb";

  return (
    <svg
      width={40}
      height={54}
      viewBox="0 0 40 54"
      style={{ margin: 2, cursor: "pointer" }}
      onClick={onClick}
    >
      <path
        d="M8 50 Q4 30 4 15 Q4 4 20 4 Q36 4 36 15 Q36 30 32 50"
        fill={cor}
        stroke={stroke}
        strokeWidth={2}
      />
      <text
        x={20}
        y={52}
        fontSize={14}
        fill="#1A1C2C"
        textAnchor="middle"
        fontWeight={600}
      >
        {numero}
      </text>
    </svg>
  );
}

function Legenda({ cor, texto }) {
  return (
    <span className="flex items-center gap-1">
      <span
        style={{
          display: "inline-block",
          width: 18,
          height: 18,
          borderRadius: "50%",
          background: cor,
          border: "1.5px solid #333",
        }}
      />
      <span style={{ color: cor }}>{texto}</span>
    </span>
  );
}
